+        mode: env.OLLAMA_API_KEY?.trim() ? "api_key" : "none",
+        source: env.OLLAMA_API_KEY?.trim() ? "env" : "none",
+      }),
+    });
+    return normalizePluginDiscoveryResult({ provider, result }).ollama as
+      | ProviderConfig
+      | undefined;
